class Solution(object):
    def minOperations(self, s1, s2, x):
        diffs = [i for i in range(len(s1)) if s1[i] != s2[i]]
        n = len(diffs)
        if n % 2 != 0:
            return -1
        if n == 0:
            return 0
        from functools import lru_cache
        @lru_cache(None)
        def dp(lo, hi):
            if lo > hi:
                return 0
            res = float('inf')
            for k in range(lo + 1, hi + 1, 2):
                cost = min(diffs[k] - diffs[lo], x)
                res = min(res, cost + dp(lo + 1, k - 1) + dp(k + 1, hi))
            return res
        return dp(0, n - 1)
